property.value:
//PostfixUnaryExpression[
    (
        pmd-kotlin:matchesSig('java.lang.StringBuilder#append(java.lang.String)')
        or pmd-kotlin:matchesSig('java.lang.StringBuffer#append(java.lang.String)')
    )
    and PostfixUnarySuffix/CallSuffix/ValueArguments/ValueArgument[
        string-length(pmd-kotlin:nodeText()) = 3
        and starts-with(pmd-kotlin:nodeText(), '"')
        and ends-with(pmd-kotlin:nodeText(), '"')
    ]
]

rule.example:
class Bad {
    fun bad(): String {
        val sb = StringBuilder()
        sb.append("x")    // violation: use append('x')
        sb.append(",")    // violation: use append(',')
        return sb.toString()
    }
}

class Good {
    fun good(): String {
        val sb = StringBuilder()
        sb.append('x')      // ok: Char literal
        sb.append(',')      // ok: Char literal
        sb.append("hello")  // ok: multi-character string
        return sb.toString()
    }
}

class Bad {
    fun afterBulkLoad() {
        System.gc()                     // violation: unpredictable, may degrade throughput
        Runtime.getRuntime().gc()       // violation: same issue
    }
}

class Good {
    fun afterBulkLoad() {
        // ok: trust the JVM garbage collector; add metrics/monitoring instead
    }
}

import java.math.BigInteger

class Bad {
    fun calc(): BigInteger {
        val zero = BigInteger.valueOf(0)   // violation: use BigInteger.ZERO
        val one  = BigInteger.valueOf(1L)  // violation: use BigInteger.ONE
        val ten  = BigInteger.valueOf(10)  // violation: use BigInteger.TEN
        return zero.add(one).add(ten)
    }
}

class Good {
    fun calc(): BigInteger {
        val zero = BigInteger.ZERO          // ok: cached constant
        val one  = BigInteger.ONE           // ok: cached constant
        val ten  = BigInteger.TEN           // ok: cached constant
        val two  = BigInteger.valueOf(2)    // ok: 2 has no named constant
        val twoAlt = 2.toBigInteger()       // ok: idiomatic Kotlin extension
        return zero.add(one).add(ten).add(two)
    }
}

property.value:
//PostfixUnaryExpression[
    (
        PostfixUnarySuffix/NavigationSuffix[@Identifier='indexOf']
        or PostfixUnarySuffix/NavigationSuffix[@Identifier='lastIndexOf']
    )
    and PostfixUnarySuffix/CallSuffix/ValueArguments/ValueArgument[
        string-length(pmd-kotlin:nodeText()) = 3
        and starts-with(pmd-kotlin:nodeText(), '"')
        and ends-with(pmd-kotlin:nodeText(), '"')
    ]
]

rule.example:
class Bad {
    fun parseHeader(line: String): Int {
        return line.indexOf(":")    // violation: use indexOf(':')
    }

    fun findLast(path: String): Int {
        return path.lastIndexOf("/")  // violation: use lastIndexOf('/')
    }
}

class Good {
    fun parseHeader(line: String): Int {
        return line.indexOf(':')    // ok: Char overload, faster
    }

    fun findLast(path: String): Int {
        return path.lastIndexOf('/')  // ok: Char overload, faster
    }

    fun multiChar(s: String): Int {
        return s.indexOf("ab")  // ok: multi-character search, no Char alternative
    }
}

class Bad {
    fun isLong(sb: StringBuilder): Boolean {
        return sb.toString().length > 100  // violation: allocates temporary String
    }
}

class Good {
    fun isLong(sb: StringBuilder): Boolean {
        return sb.length > 100  // ok: direct length property, no allocation
    }
}

import java.util.Calendar
import java.time.LocalDateTime

class Bad {
    fun currentMillis(): Long {
        return Calendar.getInstance().timeInMillis  // violation
    }
}

class Good {
    fun currentMillis(): Long {
        return System.currentTimeMillis()  // ok: no Calendar created
    }

    fun now(): LocalDateTime {
        return LocalDateTime.now()  // ok: java.time API
    }
}

import java.io.File
import java.io.FileInputStream
import java.nio.file.Files

class Bad {
    fun read(file: File): ByteArray {
        return FileInputStream(file).readBytes() // violation: use finalizer-free alternative
    }
}

class Good {
    fun read(file: File): ByteArray {
        return file.inputStream().use { it.readBytes() } // ok: extension function, no finalizer
    }

    fun readNio(file: File): ByteArray {
        return Files.newInputStream(file.toPath()).use { it.readBytes() } // ok: NIO approach
    }
}

class Bad {
    fun bad(): String {
        return String("hello") // violation: unnecessary String constructor call
    }
}

class Good {
    fun good(): String {
        return "hello" // ok: use the string literal directly
    }
}

class Bad {
    fun bad(name: String): String {
        return name.toString() // violation: toString() on a String is a no-op
    }
}

class Good {
    fun good(name: String): String {
        return name // ok: use the String variable directly
    }
}
